cat > /tmp/update_imports.sh << 'SCRIPT'
#!/bin/bash

# Pattern 1: from django.test import RequestFactory
find tests -name "*.py" -type f -exec sed -i 's/from django\.test import \(.*\)RequestFactory\(.*\)/from django.test import \1TestRequestBuilder\2/g' {} \;

# Pattern 2: from django.test.client import RequestFactory
find tests -name "*.py" -type f -exec sed -i 's/from django\.test\.client import \(.*\)RequestFactory\(.*\)/from django.test.client import \1TestRequestBuilder\2/g' {} \;

# Pattern 3: RequestFactory( - replace with TestRequestBuilder(
find tests -name "*.py" -type f -exec sed -i 's/\bRequestFactory\(/TestRequestBuilder(/g' {} \;

# Pattern 4: = RequestFactory( - replace with = TestRequestBuilder(
find tests -name "*.py" -type f -exec sed -i 's/= RequestFactory(/= TestRequestBuilder(/g' {} \;

echo "Done updating test files"
SCRIPT
chmod +x /tmp/update_imports.sh
/tmp/update_imports.sh

