import sys
sys.path.insert(0, '/workspace')

# Test 1: Import TestRequestBuilder
try:
    from django.test import TestRequestBuilder
    print("✓ Successfully imported TestRequestBuilder from django.test")
except ImportError as e:
    print(f"✗ Failed to import TestRequestBuilder: {e}")

# Test 2: Import RequestFactory (backward compatibility)
try:
    from django.test import RequestFactory
    print("✓ Successfully imported RequestFactory from django.test (backward compatibility)")
except ImportError as e:
    print(f"✗ Failed to import RequestFactory: {e}")

# Test 3: Check if they're the same class
try:
    from django.test import TestRequestBuilder, RequestFactory
    if TestRequestBuilder is RequestFactory:
        print("✓ RequestFactory is an alias for TestRequestBuilder")
    else:
        print("✗ RequestFactory is not the same as TestRequestBuilder")
except Exception as e:
    print(f"✗ Error checking alias: {e}")

# Test 4: Check class name
try:
    from django.test import TestRequestBuilder
    if TestRequestBuilder.__name__ == 'TestRequestBuilder':
        print(f"✓ Class name is correct: {TestRequestBuilder.__name__}")
    else:
        print(f"✗ Class name is incorrect: {TestRequestBuilder.__name__}")
except Exception as e:
    print(f"✗ Error checking class name: {e}")

